var cname = el.getAttribute('data-cname') || '';
var entityId = {
    entityType: 'CUSTOMER',
    id: cid
};
var entityName = cname;
widgetContext.stateController.updateState('lista_de_bombas', {
    entityId: entityId,
    entityName: entityName
});

